#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_P 100000
#define MAX_S 30

// Structure to represent a problem
typedef struct {
    int difficulty;
    int index;
} Problem;

// Comparison function for sorting problems
int compareProblems(const void *a, const void *b) {
    Problem *p1 = (Problem *)a;
    Problem *p2 = (Problem *)b;
    if (p1->difficulty != p2->difficulty) {
        return p2->difficulty - p1->difficulty;
    } else {
        return p1->index - p2->index;
    }
}

int main() {
    int P, S;
    scanf("%d %d", &P, &S);
    Problem problems[P];
    for (int i = 0; i < P; i++) {
        int scores[S], numSolved[S];
        for (int j = 0; j < S; j++) {
            scanf("%d", &scores[j]);
        }
        for (int j = 0; j < S; j++) {
            scanf("%d", &numSolved[j]);
        }
        int difficulty = 0;
        for (int j = 0; j < S - 1; j++) {
            if (numSolved[j] > numSolved[j + 1]) {
                difficulty++;
            }
        }
        problems[i].difficulty = difficulty;
        problems[i].index = i + 1;
    }
    qsort(problems, P, sizeof(Problem), compareProblems);
    for (int i = 0; i < P; i++) {
        printf("%d\n", problems[i].index);
    }
    return 0;
}

