import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int P = scanner.nextInt();
        int S = scanner.nextInt();
        Problem[] problems = new Problem[P];
        for (int i = 0; i < P; i++) {
            int[] scores = new int[S];
            int[] numSolved = new int[S];
            for (int j = 0; j < S; j++) {
                scores[j] = scanner.nextInt();
            }
            for (int j = 0; j < S; j++) {
                numSolved[j] = scanner.nextInt();
            }
            int difficulty = 0;
            for (int j = 0; j < S - 1; j++) {
                if (numSolved[j] > numSolved[j + 1]) {
                    difficulty++;
                }
            }
            problems[i] = new Problem(difficulty, i + 1);
        }
        Arrays.sort(problems);
        for (int i = 0; i < P; i++) {
            System.out.println(problems[i].index);
        }
    }
}

class Problem implements Comparable<Problem> {
    int difficulty;
    int index;
    public Problem(int difficulty, int index) {
        this.difficulty = difficulty;
        this.index = index;
    }
    @Override
    public int compareTo(Problem other) {
        if (this.difficulty != other.difficulty) {
            return other.difficulty - this.difficulty;
        } else {
            return this.index - other.index;
        }
    }
}

